jQuery(function($){$('.vh360-giving-amount').on('click',function(){$('[name="amount"]','#vh360-giving-form').val($(this).data('amount'));});$('#vh360-giving-form').on('submit',function(e){e.preventDefault();var $f=$(this),$m=$f.find('.vh360-giving-message');$m.text('Creating secure checkout...');$.post(vh360Giving.ajaxUrl,$f.serialize()+'&action=vh360_giving_create_checkout&nonce='+vh360Giving.nonce).done(function(r){if(r.success&&r.data.checkout_url){window.location=r.data.checkout_url;}else{$m.text((r.data&&r.data.message)||'Unable to start checkout.');}}).fail(function(){$m.text('Unable to start checkout.');});});$('.vh360-giving-cancel-recurring').on('click',function(){if(!confirm('Cancel this recurring gift?'))return;var $b=$(this);$b.prop('disabled',true);$.post(vh360Giving.ajaxUrl,{action:'vh360_giving_cancel_recurring',nonce:vh360Giving.nonce,recurring_id:$b.data('recurring-id')}).done(function(r){alert((r.data&&r.data.message)||'Recurring gift updated.'); if(r.success){window.location.reload();}else{$b.prop('disabled',false);}}).fail(function(){alert('Unable to cancel recurring gift.');$b.prop('disabled',false);});});});
